declare void @func_fp(float)

define void @union_nofpclass(float %v) {
; CHECK-LABEL: define {{[^@]+}}@union_nofpclass
; CHECK-SAME: (float [[V:%.*]]) {
; CHECK-NEXT:    call void @func_fp(float nofpclass(inf) [[V]])
; CHECK-NEXT:    ret void
  call void @func_fp(float nofpclass(inf) %v)
  ret void
}

